      final productDetailsResponse =
          await _iap.requestPurchase(productIdentifier: productId);
      if (productDetailsResponse.responseCode == PurchaseError.ok &&
          productDetailsResponse.purchaseToken != null) {
        print('Purchased ${productDetailsResponse.productId}');
      } else {
        print('Failed to purchase');
      }
    } catch (e) {
      print('Error during purchase: $e');
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: Text('Payment Module')),
      body: _isAvailable == null
          ? Center(child: CircularProgressIndicator())
          : Column(
              children: [
                Expanded(
                  child: ListView.builder(
                    itemCount: _items?.length,
                    itemBuilder: (context, index) {
                      final item = _items![index];
                      return ListTile(
